// Distribution Feature Extractor
// Extracts integration signals from integration/apps pages

const INTEGRATION_PATTERNS = {
  categories: {
    crm: [/salesforce/i, /hubspot/i, /pipedrive/i, /zoho\s*crm/i],
    data: [/snowflake/i, /bigquery/i, /databricks/i, /redshift/i],
    analytics: [/amplitude/i, /mixpanel/i, /heap/i, /segment/i],
    communication: [/slack/i, /teams/i, /discord/i],
    storage: [/aws\s*s3/i, /gcs/i, /azure\s*blob/i, /dropbox/i],
    auth: [/okta/i, /auth0/i, /azure\s*ad/i],
    payment: [/stripe/i, /braintree/i, /adyen/i],
    dev: [/github/i, /gitlab/i, /jira/i, /linear/i]
  },
  marketplaces: [
    { pattern: /salesforce\s*appexchange/i, name: 'salesforce_appexchange' },
    { pattern: /hubspot\s*marketplace/i, name: 'hubspot_marketplace' },
    { pattern: /slack\s*app\s*directory/i, name: 'slack_app_directory' },
    { pattern: /zapier/i, name: 'zapier' },
    { pattern: /aws\s*marketplace/i, name: 'aws_marketplace' },
    { pattern: /google\s*workspace\s*marketplace/i, name: 'google_workspace' }
  ],
  api_signals: [
    /api\s*docs/i,
    /api\s*reference/i,
    /developer\s*docs/i,
    /rest\s*api/i,
    /graphql/i,
    /webhooks/i,
    /sdk/i
  ],
  partner_patterns: [
    /partner/i,
    /certified/i,
    /premier/i,
    /gold\s*partner/i,
    /platinum/i
  ]
};

function stripHtml(html) {
  return html
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function extractIntegrations(html) {
  const text = stripHtml(html);
  const lowercaseText = text.toLowerCase();

  const integration_names = [];
  const integration_categories = {};

  // Extract by category
  for (const [category, patterns] of Object.entries(INTEGRATION_PATTERNS.categories)) {
    integration_categories[category] = [];
    for (const pattern of patterns) {
      const match = lowercaseText.match(pattern);
      if (match) {
        const name = match[0].replace(/\s+/g, ' ').trim();
        integration_names.push(name);
        integration_categories[category].push(name);
      }
    }
  }

  // Detect marketplace presence
  const marketplace_presence = [];
  for (const { pattern, name } of INTEGRATION_PATTERNS.marketplaces) {
    if (pattern.test(lowercaseText)) {
      marketplace_presence.push(name);
    }
  }

  // Detect API signals
  const has_public_api = INTEGRATION_PATTERNS.api_signals.some(p => p.test(lowercaseText));
  const api_doc_match = html.match(/href=["']([^"']*(?:api|developer|docs)[^"']*)["']/i);
  const api_doc_url = api_doc_match ? api_doc_match[1] : null;

  // Detect partner mentions
  const partner_mentions = [];
  for (const pattern of INTEGRATION_PATTERNS.partner_patterns) {
    const match = lowercaseText.match(pattern);
    if (match) {
      partner_mentions.push(match[0]);
    }
  }

  return {
    integration_count: [...new Set(integration_names)].length,
    integration_names: [...new Set(integration_names)],
    integration_categories,
    marketplace_presence: [...new Set(marketplace_presence)],
    partner_mentions: [...new Set(partner_mentions)],
    has_public_api,
    api_doc_url
  };
}

const items = $input.all();
const results = [];

for (const item of items) {
  const html = item.json.data || '';
  const features = extractIntegrations(html);

  results.push({
    json: {
      ...item.json,
      features,
      content_hash: require('crypto').createHash('md5').update(html).digest('hex'),
      extracted_at: new Date().toISOString()
    }
  });
}

return results;

// Summary node
const items = $input.all();

return [{
  json: {
    run_completed_at: new Date().toISOString(),
    signals_emitted: items.length,
    signal_ids: items.map(i => i.json.signal_id)
  }
}];
